import { createReduxStore, register } from "@wordpress/data";

const STORE_NAME = "sydney-studio";

const DEFAULT_STATE = {
  selectedCollection: "all",
  selectedType: "all",
  isModalOpen: false,
  initialCollection: null,
};

const actions = {
  setCollection(collection) {
    return { type: "SET_COLLECTION", collection };
  },
  setType(patternType) {
    return { type: "SET_TYPE", patternType };
  },
  openModal(collection = null) {
    return { type: "OPEN_MODAL", collection };
  },
  closeModal() {
    return { type: "CLOSE_MODAL" };
  },
};

function reducer(state = DEFAULT_STATE, action) {
  switch (action.type) {
    case "SET_COLLECTION":
      return { ...state, selectedCollection: action.collection };
    case "SET_TYPE":
      return { ...state, selectedType: action.patternType };
    case "OPEN_MODAL":
      return {
        ...state,
        isModalOpen: true,
        initialCollection: action.collection,
      };
    case "CLOSE_MODAL":
      return { ...state, isModalOpen: false, initialCollection: null };
  }
  return state;
}

const selectors = {
  getSelectedCollection(state) {
    return state.selectedCollection;
  },
  getSelectedType(state) {
    return state.selectedType;
  },
  isModalOpen(state) {
    return state.isModalOpen;
  },
  getInitialCollection(state) {
    return state.initialCollection;
  },
};

const store = createReduxStore(STORE_NAME, { reducer, actions, selectors });
register(store);

export { STORE_NAME };
