import { useDispatch, useSelect } from '@wordpress/data';
import { CustomSelectControl } from '@wordpress/components';
import { __ } from '@wordpress/i18n';
import { STORE_NAME } from '../store/index.js';

export function CollectionFilter() {
	const selected = useSelect( ( select ) => select( STORE_NAME ).getSelectedCollection() );
	const { setCollection } = useDispatch( STORE_NAME );
	const collections = window.sydneyStudio?.collections || {};

	const options = [
		{ key: 'all', name: __( 'All', 'sydney' ) },
		...Object.entries( collections ).map( ( [ slug, label ] ) => ( { key: slug, name: label } ) ),
	];

	function handleChange( { selectedItem } ) {
		setCollection( selectedItem.key );
	}

	return (
		<CustomSelectControl
			value={ options.find( ( o ) => o.key === selected ) }
			options={ options }
			onChange={ handleChange }
		/>
	);
}
